    public static class Interval {
        int start;
        int end;

        public Interval(int start, int end) {
            this.start = start;
            this.end = end;
        }

        public int getStart() {
            return start;
        }

        public int getEnd() {
            return end;
        }
    }

    public static class IntervalComparator implements Comparator<Interval> {
        @Override
        public int compare(Interval i1, Interval i2) {
            return i1.getStart() - i2.getStart();
        }
    }

    public static class IntervalProcessor {
        public List<Interval> findInterval(List<Interval> intervals, Interval requestInterval) {
            List<Interval> result = new ArrayList<>();
            if (intervals == null || intervals.isEmpty() || requestInterval.getEnd() < requestInterval.getStart()) {
                return result;
            }

            PriorityQueue<Interval> priorityQueue = new PriorityQueue<>(new IntervalComparator());
            priorityQueue.addAll(intervals);

            while (!priorityQueue.isEmpty() && requestInterval.getStart() >= priorityQueue.peek().getEnd()) {
                priorityQueue.remove();
            }

            int start = requestInterval.getStart();
            if (start < priorityQueue.peek().getStart()) {
                processInterval(requestInterval, priorityQueue, result, start);
            }

            start = Math.max(start, priorityQueue.remove().getEnd());
            while (!priorityQueue.isEmpty() && priorityQueue.peek().getStart() < requestInterval.getEnd()) {
                Interval current = priorityQueue.remove();
                result.add(new Interval(start, current.getStart()));
                start = current.getEnd();
            }

            if (requestInterval.getEnd() > start) {
                result.add(new Interval(start, requestInterval.getEnd()));
            }
            return result;
        }

        private void processInterval(Interval requestInterval, PriorityQueue<Interval> priorityQueue,
                                     List<Interval> result, int start) {
            if (requestInterval.getEnd() <= priorityQueue.peek().getStart()) {
                result.add(requestInterval);
            } else {
                result.add(new Interval(start, priorityQueue.peek().getStart()));
            }
        }


        public List<Interval> findInterval2(List<Interval> intervals, Interval requestInterval) {
            List<Interval> result = new ArrayList<>();
            int start = requestInterval.getStart();
            int end = requestInterval.getEnd();

            for (Interval interval : intervals) {
                // If the interval is completely before the request interval, skip it
                if (interval.getEnd() <= start) {
                    continue;
                }
                // If the interval is completely after the request interval, break the loop
                if (interval.getStart() >= end) {
                    break;
                }
                // Add the non-overlapping part to the result
                if (interval.getStart() > start) {
                    result.add(new Interval(start, interval.getStart()));
                }
                // Update start for the next iteration
                start = Math.max(start, interval.getEnd());
            }
            // Check if there's a remaining part after the last interval
            if (start < end) {
                result.add(new Interval(start, end));
            }
            return result;
        }


        public List<Interval> findNonOverlappingIntervals(List<Interval> intervals, Interval requestInterval) {
            List<Interval> result = new ArrayList<>();
            int start = requestInterval.getStart();
            int end = requestInterval.getEnd();

            for (Interval interval : intervals) {
                if (interval.getEnd() <= start || interval.getStart() >= end) {
                    // Skip intervals that do not overlap with the request interval.
                    continue;
                }
                if (interval.getStart() > start) {
                    // Add the non-overlapping part before the current interval.
                    result.add(new Interval(start, interval.getStart()));
                }
                // Update the start to be the end of the overlapping interval.
                start = Math.max(start, interval.getEnd());
            }

            // Add the remaining part of the request interval if any.
            if (start < end) {
                result.add(new Interval(start, end));
            }

            return result;
        }


