public class FindAllNonOverlappingIntervals {
    public static List<Integer[]> findInterval(List<Integer[]> intervals, Integer[] requestInterval) {
        List<Integer[]> res = new ArrayList<>();
        if (intervals == null || intervals.size() == 0 || requestInterval.length == 0
                || requestInterval[1] < requestInterval[0])
            return res;
        int start = requestInterval[0];
        int end = requestInterval[1];
        Collections.sort(intervals, (i, j) -> i[0] - j[0]);
        for (Integer[] interval : intervals) {
            int intervalStart = interval[0];
            int intervalEnd = interval[1];
            // case 1
            if (start >= intervalEnd)
                continue;
            // case 2
            if (end <= intervalStart) {
                res.add(new Integer[] { start, end });
                return res;
            }
            // case 3
            if (end <= intervalEnd) {
                res.add(new Integer[] { start, intervalStart });
                return res;
            }
            // case 4
            if (start < intervalStart) {
                res.add(new Integer[] { start, intervalStart });
            }
            // case 5
            start = intervalEnd;
        }
        if (start < end)
            res.add(new Integer[] { start, end });
        return res;
    }

    public static void main(String[] args) {
        List<Integer[]> intervals1 = new ArrayList<>();
        intervals1.add(new Integer[] { 25, 35 });
        intervals1.add(new Integer[] { 45, 65 });
        intervals1.add(new Integer[] { 85, 95 });
        intervals1.add(new Integer[] { 10, 15 });
        Integer[] request = new Integer[] { 17, 100 };
        List<Integer[]> result = findInterval(intervals1, request);
        for (Integer[] i : result) {
            System.out.println("[ " + i[0] + ", " + i[1] + " ]");
        }
    }
}
