	vector< pair<int, int> > result;
	if (in.empty()) {
		result.push_back(R);
		return result;
	}

	set< pair<int, int>, comp > s;
	for (int i = 0; i < in.size(); i++) {
		s.insert(in[i]);
	}

	set< pair<int, int> >::iterator be = s.begin(), en = s.end();

	int intS = R.first, intE = R.second;

	for (; be != en; be++) {
		pair<int, int> p = (*be);

		if (p.first > R.second) break;
		if (p.second < R.first) continue;

		int start = std::max(p.first, intS);
		int end = std::min(p.second, R.second);

		if (intS < start) {
			result.push_back(make_pair(intS, start));
		}

		intS  = min(end, intE);
	}

	if (intS != intE) {
		result.push_back(make_pair(intS, intE));
	}

	return result;
}
